PREFIX wdt: <http://www.wikidata.org/prop/direct/> PREFIX wd: <http://www.wikidata.org/entity/> SELECT ?person WHERE { wd:Q10421 wdt:P11 wd:?person ; wdt:P31 wdt:Q184235 ; wdt:P1512 wd:Q12582 . ?person wdt:P1512 ?member . ?member wdt:P31 wdt:Q1312377 . } 
GROUP BY ?person HAVING (COUNT(?member) > 0) 
ORDER BY DESC(COUNT(?member)) FILTER(lang(?person) = "en")
